    code: "// services/userService.js – identical to the Mongoose version, only the repository import changes.\n// Instead of `const userRepository = require('../repositories/userRepository');`\n// we import the pg repository: `const userRepository = require('../repositories/pgUserRepository');`\n\n// The rest of the service code is exactly the same.\n\n// controllers/userController.js – unchanged\n\n// routes/userRoutes.js – unchanged\n\n// server.js – import the routes and error handler (unchanged)\n\n// To demonstrate, here is the service file with the pg repository:\n\nconst userRepository = require('../repositories/pgUserRepository');\n\nclass UserService {\n  async register(userData) {\n    const existing = await userRepository.findByEmail(userData.email);\n    if (existing) throw new Error('Email already registered');\n    if (userData.age && (userData.age < 18 || userData.age > 120)) {\n      throw new Error('Age must be between 18 and 120');\n    }\n    // In a real app, hash password here (or use database trigger).\n    const user = await userRepository.create(userData);\n    delete user.password; // if returned\n    return user;\n  }\n\n  // ... other methods identical to the Mongoose version\n}\n\nmodule.exports = new UserService();\n\n// This demonstrates that swapping the database only required changing the repository import.\n// The rest of the application stayed exactly the same.\n",
