    keywords: ["bcrypt", "password hashing", "salt", "compare", "security"],
    explanation:
      "Passwords must never be stored in plain text. bcrypt is a widely used hashing algorithm that incorporates a salt and is deliberately slow to resist brute‑force attacks. The salt is stored inside the hash string.\n\n**Important:** Hash passwords before inserting into the database. In the Mongoose model we used a `pre('save')` hook; in PostgreSQL we need to do it in the service layer or via a database trigger.\n\n**Incremental step:** Next we will implement JWT authentication for login and protected routes.",
    code: "// services/userService.js (registration part)\nconst bcrypt = require('bcryptjs');\nconst userRepository = require('../repositories/pgUserRepository');\n\nasync function register(userData) {\n  const { email, password, name, age } = userData;\n\n  // Check if user exists\n  const existing = await userRepository.findByEmail(email);\n  if (existing) throw new Error('Email already registered');\n\n  // Hash password\n  const saltRounds = 10;\n  const hashedPassword = await bcrypt.hash(password, saltRounds);\n\n  const user = await userRepository.create({\n    name,\n    email,\n    password: hashedPassword,\n    age\n  });\n  // Remove password from returned object\n  delete user.password;\n  return user;\n}\n\nasync function login(email, plainPassword) {\n  const user = await userRepository.findByEmail(email);\n  if (!user) throw new Error('Invalid credentials');\n\n  const isMatch = await bcrypt.compare(plainPassword, user.password);\n  if (!isMatch) throw new Error('Invalid credentials');\n\n  // Return user without password\n  delete user.password;\n  return user;\n}\n\nmodule.exports = { register, login, /* ... */ };\n\n// For Mongoose, the same bcrypt methods can be used in the model's pre‑save hook.\n// Example in User schema:\n// userSchema.pre('save', async function(next) {\n//   if (!this.isModified('password')) return next();\n//   this.password = await bcrypt.hash(this.password, 10);\n//   next();\n// });\n//\n// userSchema.methods.comparePassword = async function(candidate) {\n//   return bcrypt.compare(candidate, this.password);\n// };\n",
