    id: "jwt-login-endpoint",
    type: "implementation",
    topic: "Authentication",
    title: "Login endpoint that returns JWT access token",
    difficulty: "Medium",
    prompt:
      "Implement a login endpoint `POST /api/auth/login` that accepts email and password, validates credentials using bcrypt, and returns a JWT access token. Use the repository and service layers.",
    expected:
      "Controller receives email and password, calls AuthService.login(). Service finds the user by email, compares password with bcrypt, then generates a JWT using the utility. The token is returned to the client. Invalid credentials return 401.",
    keywords: ["login", "JWT", "bcrypt", "authentication", "express"],
    explanation:
      "The login flow:\n1. Client sends email + password.\n2. Server looks up user by email.\n3. If user not found, return 401.\n4. Compare plain password with stored hash using bcrypt.\n5. If mismatch, return 401.\n6. Generate JWT payload (e.g., `{ userId, email, role }`).\n7. Sign token with expiry (e.g., 1 hour).\n8. Return token to client (in JSON body).\n\n**Incremental step:** Next we will protect routes using middleware that verifies the JWT.",
    code: "// services/authService.js\nconst bcrypt = require('bcryptjs');\nconst userRepository = require('../repositories/pgUserRepository'); // or mongoose version\nconst { generateToken } = require('../utils/jwt');\n\nclass AuthService {\n  async login(email, plainPassword) {\n    // 1. Find user by email\n    const user = await userRepository.findByEmail(email);\n    if (!user) {\n      throw new Error('Invalid credentials');\n    }\n\n    // 2. Compare password\n    const isMatch = await bcrypt.compare(plainPassword, user.password);\n    if (!isMatch) {\n      throw new Error('Invalid credentials');\n    }\n\n    // 3. Generate JWT (omit password from payload)\n    const payload = {\n      userId: user.id,\n      email: user.email,\n      role: user.role || 'user'\n    };\n    const token = generateToken(payload, '1h');\n\n    // 4. Return token and user info (without password)\n    const { password, ...userWithoutPassword } = user;\n    return { token, user: userWithoutPassword };\n  }\n}\n\nmodule.exports = new AuthService();\n\n// controllers/authController.js\nconst authService = require('../services/authService');\n\nclass AuthController {\n  async login(req, res, next) {\n    try {\n      const { email, password } = req.body;\n      if (!email || !password) {\n        return res.status(400).json({ error: 'Email and password are required' });\n      }\n      const result = await authService.login(email, password);\n      res.json(result);\n    } catch (err) {\n      if (err.message === 'Invalid credentials') {\n        return res.status(401).json({ error: err.message });\n      }\n      next(err);\n    }\n  }\n}\n\nmodule.exports = new AuthController();\n\n// routes/authRoutes.js\nconst express = require('express');\nconst router = express.Router();\nconst authController = require('../controllers/authController');\n\nrouter.post('/login', express.json(), authController.login);\n\nmodule.exports = router;\n\n// server.js – mount route\n// app.use('/api/auth', authRoutes);\n",
