      "Authentication identifies the user; authorization determines what they can do. Role‑based access control is a common model: each user has one or more roles (e.g., 'admin', 'user'). The middleware restricts access to certain routes based on the role.\n\n**Typical roles:** 'admin', 'moderator', 'user'.\nThe `requireRole` middleware can be used after `authenticate` (which sets `req.user`).\n\n**Incremental step:** Next we will implement OAuth2 login with Google (Passport.js).",
    code: "// middlewares/authMiddleware.js (extend with role checker)\nconst requireRole = (allowedRoles) => {\n  return (req, res, next) => {\n    if (!req.user) {\n      return res.status(401).json({ error: 'Authentication required' });\n    }\n    if (!allowedRoles.includes(req.user.role)) {\n      return res.status(403).json({ error: 'Forbidden: insufficient privileges' });\n    }\n    next();\n  };\n};\n\n// Example usage:\n// routes/adminRoutes.js\nconst { authenticate } = require('../middlewares/authMiddleware');\nconst { requireRole } = require('../middlewares/authMiddleware');\n\nrouter.get('/dashboard', authenticate, requireRole(['admin']), (req, res) => {\n  res.json({ message: 'Welcome admin' });\n});\n\n// You can also combine multiple roles\nrouter.get('/moderator', authenticate, requireRole(['admin', 'moderator']), (req, res) => {\n  res.json({ message: 'Welcome moderator' });\n});\n\n// If you want to check permissions dynamically, you can also use a permission-based system\nconst requirePermission = (permission) => {\n  return (req, res, next) => {\n    if (!req.user || !req.user.permissions.includes(permission)) {\n      return res.status(403).json({ error: 'Forbidden' });\n    }\n    next();\n  };\n};\n",
