    explanation:
      "OAuth2 allows users to authenticate using their Google account without storing passwords. Passport.js is a popular authentication middleware for Node.js. The `passport-google-oauth20` strategy implements the OAuth2 flow.\n\n**Steps:**\n1. Register OAuth application in Google Cloud Console, get Client ID and Secret.\n2. Install `passport`, `passport-google-oauth20`, `express-session` (required for Passport).\n3. Configure Google strategy with `clientID`, `clientSecret`, `callbackURL`.\n4. Serialize/deserialize user (or skip if using JWT).\n5. Create routes: `/auth/google`, `/auth/google/callback`.\n6. After callback, issue a JWT and redirect to frontend with token (or set cookie).\n\n**Incremental step:** After OAuth, we will add session‑based authentication as an alternative.",
    code: "// config/passport.js\nconst passport = require('passport');\nconst GoogleStrategy = require('passport-google-oauth20').Strategy;\nconst User = require('../models/User'); // MongoDB user model\n\npassport.use(new GoogleStrategy({\n    clientID: process.env.GOOGLE_CLIENT_ID,\n    clientSecret: process.env.GOOGLE_CLIENT_SECRET,\n    callbackURL: '/api/auth/google/callback',\n    passReqToCallback: true\n  },\n  async (req, accessToken, refreshToken, profile, done) => {\n    try {\n      let user = await User.findOne({ email: profile.emails[0].value });\n      if (!user) {\n        user = await User.create({\n          name: profile.displayName,\n          email: profile.emails[0].value,\n          googleId: profile.id,\n          isVerified: true\n        });\n      }\n      return done(null, user);\n    } catch (err) {\n      return done(err, null);\n    }\n  }\n));\n\npassport.serializeUser((user, done) => done(null, user.id));\npassport.deserializeUser(async (id, done) => {\n  try {\n    const user = await User.findById(id);\n    done(null, user);\n  } catch (err) {\n    done(err, null);\n  }\n});\n\nmodule.exports = passport;\n\n// server.js – setup sessions\nconst session = require('express-session');\nconst passport = require('./config/passport');\napp.use(session({ secret: 'some-secret', resave: false, saveUninitialized: false }));\napp.use(passport.initialize());\napp.use(passport.session());\n\n// routes/authRoutes.js\nrouter.get('/google', passport.authenticate('google', { scope: ['profile', 'email'] }));\nrouter.get('/google/callback',\n  passport.authenticate('google', { failureRedirect: '/login' }),\n  (req, res) => {\n    // Generate JWT for frontend\n    const token = generateToken({ userId: req.user.id, email: req.user.email, role: req.user.role });\n    res.redirect(`https://frontend.com/auth/callback?token=${token}`);\n  }\n);\n",
