    id: "session-auth-express",
    type: "implementation",
    topic: "Authentication",
    title:
      "Session‑based authentication with express‑session and MongoDB store",
    difficulty: "Medium",
    prompt:
      "Implement session‑based authentication using `express-session` and `connect-mongodb-session` (or `connect-pg-simple`). Create login and logout endpoints that store the user ID in the session store. Protect routes with a middleware that checks `req.session.userId`.",
    expected:
      "After successful login, `req.session.userId = user.id`. The session ID is stored in a cookie and the session data is persisted in the database. The middleware checks for `req.session.userId` and returns 401 if absent. Logout destroys the session.",
    keywords: [
      "session",
      "express-session",
      "cookie",
      "store",
      "login",
      "logout",
    ],
    explanation:
      "Session‑based authentication is stateful: the server stores session data (e.g., user ID) in a database or memory, and the client only holds a session cookie (with the session ID). This is simpler than JWT for basic applications, but requires a shared session store for scale.\n\n**Key packages:** `express-session`, `connect-mongodb-session` (for MongoDB) or `connect-pg-simple` (for PostgreSQL).\n\n**Incremental step:** Next we will implement pagination for API endpoints.",
    code: "// config/session.js\nconst session = require('express-session');\nconst MongoStore = require('connect-mongodb-session')(session);\n\nconst store = new MongoStore({\n  uri: process.env.MONGODB_URI,\n  collection: 'sessions',\n  expires: 1000 * 60 * 60 * 24 * 7 // 7 days\n});\n\nstore.on('error', (err) => console.error('Session store error:', err));\n\nconst sessionMiddleware = session({\n  secret: process.env.SESSION_SECRET,\n  resave: false,\n  saveUninitialized: false,\n  store,\n  cookie: {\n    httpOnly: true,\n    secure: process.env.NODE_ENV === 'production',\n    sameSite: 'lax',\n    maxAge: 1000 * 60 * 60 * 24 * 7\n  }\n});\n\nmodule.exports = sessionMiddleware;\n\n// server.js – use session middleware\napp.use(sessionMiddleware);\n\n// services/authService.js (login using sessions)\nasync function loginWithSession(email, password, req) {\n  const user = await userRepository.findByEmail(email);\n  if (!user) throw new Error('Invalid credentials');\n  const isMatch = await bcrypt.compare(password, user.password);\n  if (!isMatch) throw new Error('Invalid credentials');\n  // Store userId in session\n  req.session.userId = user.id;\n  req.session.userRole = user.role;\n  return user;\n}\n\nfunction logout(req) {\n  return new Promise((resolve, reject) => {\n    req.session.destroy((err) => {\n      if (err) reject(err);\n      else resolve();\n    });\n  });\n}\n\n// controllers/authController.js\nasync login(req, res, next) {\n  try {\n    const { email, password } = req.body;\n    const user = await authService.loginWithSession(email, password, req);\n    res.json({ message: 'Logged in', user });\n  } catch (err) {\n    next(err);\n  }\n}\n\nasync logout(req, res, next) {\n  try {\n    await authService.logout(req);\n    res.clearCookie('connect.sid'); // session cookie name\n    res.json({ message: 'Logged out' });\n  } catch (err) {\n    next(err);\n  }\n}\n\n// auth middleware for session\nconst requireSession = (req, res, next) => {\n  if (!req.session.userId) {\n    return res.status(401).json({ error: 'Unauthorized' });\n  }\n  next();\n};\n",
