    explanation:
      "Rate limiting protects APIs from abuse. When using multiple server instances, an in‑memory store would not be shared, so users could exceed limits by hitting different instances. A Redis store centralises counters, ensuring consistency.\n\n**Incremental step:** Next, we will add custom key generation (e.g., by user ID for authenticated endpoints).",
    code: "// middlewares/rateLimiter.js\nconst rateLimit = require('express-rate-limit');\nconst RedisStore = require('rate-limit-redis');\nconst redisClient = require('../config/redis');\n\n// General API limiter\nconst apiLimiter = rateLimit({\n  store: new RedisStore({\n    sendCommand: (...args) => redisClient.call(...args),\n  }),\n  windowMs: 15 * 60 * 1000, // 15 minutes\n  max: 100, // limit each IP to 100 requests per windowMs\n  standardHeaders: true, // Return rate limit info in the `RateLimit-*` headers\n  legacyHeaders: false,\n  message: { error: 'Too many requests, please try again later.' },\n  keyGenerator: (req) => req.ip, // default: IP address\n});\n\n// Stricter limiter for auth endpoints (login, register)\nconst authLimiter = rateLimit({\n  store: new RedisStore({\n    sendCommand: (...args) => redisClient.call(...args),\n  }),\n  windowMs: 15 * 60 * 1000,\n  max: 5, // 5 attempts per 15 minutes\n  skipSuccessfulRequests: true, // only count failed requests\n});\n\nmodule.exports = { apiLimiter, authLimiter };\n\n// Apply in server.js or routes:\n// app.use('/api/', apiLimiter); // applies to all routes starting with /api/\n// app.use('/api/auth/login', authLimiter);\n",
