    code: "// server.js – integrate Socket.IO\nconst express = require('express');\nconst http = require('http');\nconst { Server } = require('socket.io');\nconst jwt = require('jsonwebtoken');\n\nconst app = express();\nconst server = http.createServer(app);\nconst io = new Server(server, {\n  cors: { origin: '*' }\n});\n\n// Authentication middleware for Socket.IO\nio.use((socket, next) => {\n  const token = socket.handshake.auth.token;\n  if (!token) return next(new Error('Authentication error'));\n  try {\n    const decoded = jwt.verify(token, process.env.JWT_SECRET);\n    socket.user = decoded;\n    next();\n  } catch (err) {\n    next(new Error('Invalid token'));\n  }\n});\n\nio.on('connection', (socket) => {\n  console.log(`User ${socket.user.userId} connected`);\n\n  // Join a room uniquely identified by user ID\n  socket.join(`user:${socket.user.userId}`);\n\n  socket.on('disconnect', () => {\n    console.log(`User ${socket.user.userId} disconnected`);\n  });\n});\n\n// In post creation controller, after saving post:\nconst io = require('../server').io; // or export from server\nio.to(`user:${post.authorId}`).emit('notification', {\n  type: 'post_created',\n  message: 'Your post has been created!'\n});\n\n// To broadcast to all connected clients:\n// io.emit('global_notification', { text: 'New post published' });\n\n// Client side (browser):\n/*\nconst socket = io('http://localhost:3000', {\n  auth: { token: localStorage.getItem('token') }\n});\nsocket.on('notification', (data) => console.log(data));\n*/\n",
