    code: "// queues/emailQueue.js\nconst { Queue, Worker } = require('bullmq');\nconst redisConfig = { connection: { host: 'localhost', port: 6379 } };\n\n// Create queue\nconst emailQueue = new Queue('email', redisConfig);\n\n// Function to add a job to the queue\nexport const sendWelcomeEmail = async (userId, email, name) => {\n  const job = await emailQueue.add('welcome', { userId, email, name }, {\n    attempts: 3,\n    backoff: { type: 'exponential', delay: 1000 },\n    removeOnComplete: true,\n  });\n  return job;\n};\n\n// Worker that processes jobs\nconst emailWorker = new Worker('email', async (job) => {\n  const { userId, email, name } = job.data;\n  console.log(`Processing email for ${email}`);\n  job.updateProgress(20);\n\n  // Simulate email sending...\n  await new Promise(resolve => setTimeout(resolve, 2000));\n  job.updateProgress(80);\n\n  // After success, mark as done\n  console.log(`Welcome email sent to ${email}`);\n  job.updateProgress(100);\n  return { success: true };\n}, redisConfig);\n\nemailWorker.on('completed', (job) => {\n  console.log(`Job ${job.id} completed`);\n});\n\nemailWorker.on('failed', (job, err) => {\n  console.error(`Job ${job.id} failed:`, err);\n});\n\n// In controller after user registration:\n// await sendWelcomeEmail(user.id, user.email, user.name);\n\n// To monitor queue progress, expose an endpoint or use bull-board UI.\n",
