    code: "// tracing.js (must be imported first, before any other imports)\nconst { NodeTracerProvider } = require('@opentelemetry/sdk-trace-node');\nconst { JaegerExporter } = require('@opentelemetry/exporter-jaeger');\nconst { BatchSpanProcessor } = require('@opentelemetry/sdk-trace-base');\nconst { registerInstrumentations } = require('@opentelemetry/instrumentation');\nconst { ExpressInstrumentation } = require('@opentelemetry/instrumentation-express');\nconst { HttpInstrumentation } = require('@opentelemetry/instrumentation-http');\nconst { PgInstrumentation } = require('@opentelemetry/instrumentation-pg');\n\nconst provider = new NodeTracerProvider({\n  serviceName: 'my-express-service',\n});\n\n// Exporter to Jaeger (running on localhost:6832)\nconst exporter = new JaegerExporter({\n  endpoint: 'http://localhost:14268/api/traces',\n});\nprovider.addSpanProcessor(new BatchSpanProcessor(exporter));\nprovider.register();\n\n// Auto‑instrument HTTP and Express\nregisterInstrumentations({\n  instrumentations: [\n    new HttpInstrumentation(),\n    new ExpressInstrumentation(),\n    new PgInstrumentation(), // if using pg\n  ],\n});\n\n// In server.js, import tracing at the very top:\n// require('./tracing');\n\n// You can also create custom spans:\n// const tracer = require('@opentelemetry/api').trace.getTracer('my-custom');\n// const span = tracer.startSpan('processOrder');\n// span.end();\n",
